from dataclasses import dataclassimport jsonimport pandas as pdfrom criresviz.common import OPACITYfrom criresviz.models.feature import find_active_regions@dataclass(slots=True)class Molecule:    name: str    active_regions: list    temperature: float    pressure: float    wavelength_range: list    opacity_mode: str    threshold: float    source: str    '''    Properties    '''    '''    Methods    '''    @classmethod    def from_name(cls, name):            with open(OPACITY / f"{name}.json") as f:            data = json.load(f)                return cls(            name=data["species"],            active_regions=[                tuple(region)                for region in data["active_regions"]            ],            temperature=data["temperature"],            pressure=data["pressure"],            wavelength_range=data["wavelenght_range"],            opacity_mode=data["opacity_mode"],            threshold=data["threshold"],            source=data["source"],        )    ##############################################    def __str__(self):            wmin, wmax = self.wavelength_range            return (            "Molecule\n"            "──────────────────────────────\n"            f"Name:              {self.name}\n"            f"Temperature:       {self.temperature:.0f} K\n"            f"Pressure:          {self.pressure/1e5:.1f} bar\n"            f"Wavelength range:  {wmin:.2f}–{wmax:.2f} μm"        )        ##############################################    